const numbersToWords=a=>{const n=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(a<0x14)return n[a];if(a<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](a/0xa)]+(a%0xa?'\x20'+n[a%0xa]:'');if(a<0x3e8){const m=Math['floor'](a/0x64),W=a%0x64;return(0x1===m?'εκατό':0x2===m?'διακόσια':0x3===m?'τριακόσια':0x4===m?'τετρακόσια':0x5===m?'πεντακόσια':0x6===m?'εξακόσια':0x7===m?'επτακόσια':0x8===m?'οκτακόσια':0x9===m?'εννιακόσια':'')+(W?'\x20'+numbersToWords(W):'');}return a<0xf4240?numbersToWords(Math['floor'](a/0x3e8))+'\x20χιλιάδες'+(a%0x3e8?'\x20'+numbersToWords(a%0x3e8):''):numbersToWords(Math['floor'](a/0xf4240))+'\x20εκατομμύρια'+(a%0xf4240?'\x20'+numbersToWords(a%0xf4240):'');},numberToText=(a,m='money')=>{const W=Math['floor'](a),j=Math['round'](0x64*(a-W));let N=numbersToWords(W),C=j>0x0?numbersToWords(j):'';switch(m){case'money':return C?N+'\x20ευρώ\x20και\x20'+C+'\x20λεπτά':N+'\x20ευρώ';case'time':return C?N+'\x20ώρες\x20και\x20'+C+'\x20λεπτά':N+'\x20ώρες';default:return C?N+'\x20και\x20'+C:''+N;}};